using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default renderer changed from System to Professional.
        // Explicitly set RenderMode to preserve the .NET 8 visual appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }

    public string DisplayName { get; set; }

    [Editor(typeof(MaxItemsEditor), typeof(UITypeEditor))]
    public int MaxItems { get; set; }
}

internal class MaxItemsEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        var svc = provider?.GetService(typeof(IWindowsFormsEditorService))
                  as IWindowsFormsEditorService;
        if (svc is null) return value;

        var control = BuildDropDown(value);

        // .NET 9: DropDownControl now throws ArgumentNullException on null.
        // Guard against null before calling.
        if (control is null) return value;

        svc.DropDownControl(control);
        return control.Tag ?? value;
    }

    private static Control? BuildDropDown(object currentValue)
    {
        var list = new ListBox();
        list.Items.AddRange(new object[] { 5, 10, 25, 50 });
        list.Tag = currentValue;
        list.SelectedItem = currentValue;
        list.Click += (s, e) =>
        {
            if (s is ListBox lb && lb.SelectedItem is not null)
                lb.Tag = lb.SelectedItem;
        };
        return list;
    }
}

